import{_ as a,c as o,o as s,a1 as d}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Compatibilidade: Skills do Claude Code | opencode-agent-skills","description":"Aprenda como o OpenCode Agent Skills é compatível com skills e plugins do Claude Code. Domine o mecanismo de mapeamento de ferramentas, prioridade de descoberta de skills e reutilize o ecossistema de skills do Claude.","frontmatter":{"title":"Compatibilidade: Skills do Claude Code | opencode-agent-skills","sidebarTitle":"Reutilizar Skills do Claude","subtitle":"Compatibilidade com Skills do Claude Code","description":"Aprenda como o OpenCode Agent Skills é compatível com skills e plugins do Claude Code. Domine o mecanismo de mapeamento de ferramentas, prioridade de descoberta de skills e reutilize o ecossistema de skills do Claude.","tags":["Compatibilidade","Claude Code","Reutilização de Skills"],"prerequisite":["start-what-is-opencode-agent-skills","platforms-skill-discovery-mechanism"],"order":1},"headers":[],"relativePath":"pt/joshuadavidthomas/opencode-agent-skills/advanced/claude-code-compatibility/index.md","filePath":"pt/joshuadavidthomas/opencode-agent-skills/advanced/claude-code-compatibility/index.md"}'),i={name:"pt/joshuadavidthomas/opencode-agent-skills/advanced/claude-code-compatibility/index.md"};function l(t,e,r,n,c,p){return s(),o("div",null,[...e[0]||(e[0]=[d(`<h1 id="compatibilidade-com-skills-do-claude-code" tabindex="-1">Compatibilidade com Skills do Claude Code <a class="header-anchor" href="#compatibilidade-com-skills-do-claude-code" aria-label="Permalink to &quot;Compatibilidade com Skills do Claude Code&quot;">​</a></h1><h2 id="o-que-voce-vai-aprender" tabindex="-1">O Que Você Vai Aprender <a class="header-anchor" href="#o-que-voce-vai-aprender" aria-label="Permalink to &quot;O Que Você Vai Aprender&quot;">​</a></h2><ul><li>Entender como o plugin é automaticamente compatível com o formato de skills do Claude Code</li><li>Dominar o mecanismo de mapeamento de ferramentas para que skills do Claude funcionem corretamente no OpenCode</li><li>Conhecer as regras completas de prioridade na descoberta de skills</li><li>Reutilizar skills existentes do marketplace de plugins do Claude sem precisar reescrevê-las</li></ul><h2 id="seu-desafio-atual" tabindex="-1">Seu Desafio Atual <a class="header-anchor" href="#seu-desafio-atual" aria-label="Permalink to &quot;Seu Desafio Atual&quot;">​</a></h2><p>Você já tem algumas skills do Claude Code, ou quer usar skills do marketplace de plugins do Claude, mas essas skills foram escritas para o Claude Code. Usá-las diretamente no OpenCode causa problemas:</p><ul><li>Chamadas de ferramentas nas skills do Claude (como <code>TodoWrite</code>, <code>Task</code>) não existem no OpenCode</li><li>Não está claro como fazer o OpenCode encontrar skills de plugins do Claude já instalados</li><li>Preocupação com incompatibilidade de formato, exigindo reescrever todo o conteúdo</li></ul><h2 id="conceito-central" tabindex="-1">Conceito Central <a class="header-anchor" href="#conceito-central" aria-label="Permalink to &quot;Conceito Central&quot;">​</a></h2><p>O plugin OpenCode Agent Skills usa um <strong>mecanismo de compatibilidade em três camadas</strong> que permite usar skills do Claude Code sem modificações:</p><ol><li><strong>Descoberta Automática</strong> - Escaneia skills dos diretórios padrão do Claude Code (<code>.claude/skills/</code>, <code>~/.claude/plugins/</code>)</li><li><strong>Mapeamento de Ferramentas</strong> - Injeta automaticamente um guia de mapeamento ao carregar skills, convertendo nomes de ferramentas do Claude para nomes do OpenCode</li><li><strong>Suporte a Formatos</strong> - Suporta tanto o formato v1 quanto v2 de instalação de plugins do Claude</li></ol><div class="info custom-block"><p class="custom-block-title">Conceito-Chave</p><p><strong>Formato de Skills do Claude Code</strong> - Especificação de skills definida pela Anthropic, usando arquivos <code>SKILL.md</code> para descrever skills, contendo YAML frontmatter (metadados) e conteúdo Markdown (instruções).</p></div><h3 id="como-funciona-o-mapeamento-de-ferramentas" tabindex="-1">Como Funciona o Mapeamento de Ferramentas <a class="header-anchor" href="#como-funciona-o-mapeamento-de-ferramentas" aria-label="Permalink to &quot;Como Funciona o Mapeamento de Ferramentas&quot;">​</a></h3><p>Quando o plugin detecta que uma skill carregada foi escrita para o Claude Code, ele injeta automaticamente um guia de mapeamento de ferramentas:</p><table tabindex="0"><thead><tr><th>Ferramenta Claude Code</th><th>Ferramenta OpenCode</th><th>Regra de Mapeamento</th></tr></thead><tbody><tr><td><code>TodoWrite/TodoRead</code></td><td><code>todowrite/todoread</code></td><td>Minúsculas</td></tr><tr><td><code>Task</code> (sub-agente)</td><td><code>task</code> (com parâmetro subagent_type)</td><td>Usar parâmetro</td></tr><tr><td><code>Skill</code></td><td><code>use_skill</code></td><td>Substituir nome</td></tr><tr><td><code>Read/Write/Edit/Bash/Glob/Grep/WebFetch</code></td><td><code>read/write/edit/bash/glob/grep/webfetch</code></td><td>Minúsculas</td></tr></tbody></table><p><strong>Método de Mapeamento</strong>: O plugin injeta o guia de mapeamento como XML no contexto da sessão ao carregar a skill, e a IA automaticamente chama a ferramenta correta seguindo o mapeamento.</p><div class="tip custom-block"><p class="custom-block-title">Por Que o Mapeamento é Necessário?</p><p>Claude Code e OpenCode têm estilos de nomenclatura de ferramentas diferentes. Claude usa PascalCase (como <code>TodoWrite</code>), OpenCode usa minúsculas (como <code>todowrite</code>). O mapeamento de ferramentas informa à IA como converter as chamadas.</p></div><h3 id="prioridade-de-descoberta-de-skills" tabindex="-1">Prioridade de Descoberta de Skills <a class="header-anchor" href="#prioridade-de-descoberta-de-skills" aria-label="Permalink to &quot;Prioridade de Descoberta de Skills&quot;">​</a></h3><p>O plugin descobre skills na seguinte ordem, <strong>a primeira skill correspondente tem efeito</strong> (skills com mesmo nome não são duplicadas):</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[Fluxo de Descoberta de Skills] --&gt; B[OpenCode Nível Projeto]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; |.opencode/skills/| C[1. project]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[Claude Code Nível Projeto]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; |.claude/skills/| E[2. claude-project]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F[OpenCode Nível Usuário]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; |~/.config/opencode/skills/| G[3. user]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; H[Claude Code Nível Usuário]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    H --&gt; |~/.claude/skills/| I[4. claude-user]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    I --&gt; J[Cache de Plugins Claude]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    J --&gt; |~/.claude/plugins/cache/| K[5. claude-plugins]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    K --&gt; L[Marketplace de Plugins Claude]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    L --&gt; |~/.claude/plugins/marketplaces/| M[6. claude-plugins]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style C fill:#e1f5e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style E fill:#fff4e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style G fill:#e1f5e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style I fill:#fff4e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style K fill:#fff4e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style M fill:#fff4e1</span></span></code></pre></div><p><strong>Regras de Prioridade</strong>:</p><ul><li>Skills de nível projeto sobrescrevem skills de nível usuário (conveniente para personalização de projeto)</li><li>Skills do OpenCode têm prioridade sobre skills do Claude (evita confusão)</li><li>Skills com mesmo nome mantêm apenas a primeira versão descoberta</li></ul><details class="details custom-block"><summary>Exemplo: Sobrescrita de Skills com Mesmo Nome</summary><p>Suponha que você tenha uma skill chamada <code>git-helper</code> em dois locais:</p><ul><li><code>.claude/skills/git-helper/SKILL.md</code> (versão Claude)</li><li><code>.opencode/skills/git-helper/SKILL.md</code> (versão OpenCode)</li></ul><p><strong>Resultado</strong>: A versão OpenCode tem efeito (prioridade mais alta)</p></details><h2 id="🎒-antes-de-comecar" tabindex="-1">🎒 Antes de Começar <a class="header-anchor" href="#🎒-antes-de-comecar" aria-label="Permalink to &quot;🎒 Antes de Começar&quot;">​</a></h2><ul><li>OpenCode Agent Skills plugin instalado e configurado</li><li>Familiaridade com conceitos básicos de skills (recomendado ler primeiro <a href="./../../start/what-is-opencode-agent-skills/">O Que é OpenCode Agent Skills?</a>)</li><li>(Opcional) Ter plugins ou skills do Claude Code já instalados</li></ul><h2 id="maos-a-obra" tabindex="-1">Mãos à Obra <a class="header-anchor" href="#maos-a-obra" aria-label="Permalink to &quot;Mãos à Obra&quot;">​</a></h2><h3 id="passo-1-verificar-se-as-skills-do-claude-foram-descobertas" tabindex="-1">Passo 1: Verificar se as Skills do Claude Foram Descobertas <a class="header-anchor" href="#passo-1-verificar-se-as-skills-do-claude-foram-descobertas" aria-label="Permalink to &quot;Passo 1: Verificar se as Skills do Claude Foram Descobertas&quot;">​</a></h3><p><strong>Por quê</strong> Confirmar que o plugin consegue escanear corretamente seus diretórios de skills do Claude Code.</p><p>No OpenCode, chame a ferramenta:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>get_available_skills()</span></span></code></pre></div><p><strong>Você deve ver</strong>: A lista de skills retornada inclui skills de <code>.claude/skills/</code>, <code>~/.claude/skills/</code>, <code>~/.claude/plugins/</code>, com o campo <code>source</code> de cada skill mostrando a origem (como <code>claude-project</code>, <code>claude-user</code>, <code>claude-plugins</code>).</p><p><strong>Checkpoint ✅</strong>: Confirme que a lista inclui as skills do Claude esperadas.</p><h3 id="passo-2-carregar-uma-skill-do-claude" tabindex="-1">Passo 2: Carregar uma Skill do Claude <a class="header-anchor" href="#passo-2-carregar-uma-skill-do-claude" aria-label="Permalink to &quot;Passo 2: Carregar uma Skill do Claude&quot;">​</a></h3><p><strong>Por quê</strong> Verificar se o mecanismo de mapeamento de ferramentas está funcionando corretamente.</p><p>Chame a ferramenta para carregar uma skill do Claude:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>use_skill(skill=&quot;nome-da-sua-skill&quot;)</span></span></code></pre></div><p><strong>Você deve ver</strong>: Mensagem de sucesso retornada, como <code>Skill &quot;xxx&quot; loaded.</code>.</p><p><strong>Checkpoint ✅</strong>: A IA agora pode usar as instruções dessa skill.</p><h3 id="passo-3-verificar-se-o-mapeamento-de-ferramentas-esta-funcionando" tabindex="-1">Passo 3: Verificar se o Mapeamento de Ferramentas Está Funcionando <a class="header-anchor" href="#passo-3-verificar-se-o-mapeamento-de-ferramentas-esta-funcionando" aria-label="Permalink to &quot;Passo 3: Verificar se o Mapeamento de Ferramentas Está Funcionando&quot;">​</a></h3><p><strong>Por quê</strong> Confirmar que a IA consegue chamar corretamente as ferramentas do OpenCode em vez das ferramentas do Claude.</p><p>Peça à IA uma tarefa que requer as ferramentas da skill, por exemplo:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Por favor, use a funcionalidade de todo da skill para criar uma lista de tarefas para mim.</span></span></code></pre></div><p><strong>Você deve ver</strong>: A IA chama corretamente a ferramenta <code>todowrite</code> do OpenCode, não a ferramenta <code>TodoWrite</code> do Claude.</p><div class="tip custom-block"><p class="custom-block-title">Como Verificar se o Mapeamento Está Funcionando?</p><p>Verifique o log de chamadas de ferramentas da IA (se o modo de depuração estiver habilitado), você verá que ela está chamando <code>todowrite</code> em vez de <code>TodoWrite</code>.</p></div><p><strong>Checkpoint ✅</strong>: Chamada de ferramenta bem-sucedida, tarefa concluída.</p><h2 id="armadilhas-comuns" tabindex="-1">Armadilhas Comuns <a class="header-anchor" href="#armadilhas-comuns" aria-label="Permalink to &quot;Armadilhas Comuns&quot;">​</a></h2><h3 id="_1-incompatibilidade-de-formato-de-plugin" tabindex="-1">1. Incompatibilidade de Formato de Plugin <a class="header-anchor" href="#_1-incompatibilidade-de-formato-de-plugin" aria-label="Permalink to &quot;1. Incompatibilidade de Formato de Plugin&quot;">​</a></h3><p><strong>Problema</strong>: Plugins antigos do Claude usam formato v1, novos usam formato v2, fazendo com que algumas skills não sejam descobertas.</p><p><strong>Causa</strong>: As estruturas de <code>installed_plugins.json</code> v1 e v2 são diferentes.</p><p><strong>Solução</strong>: O plugin suporta ambos os formatos, não é necessária conversão manual. Se as skills ainda não forem descobertas, verifique se <code>~/.claude/plugins/installed_plugins.json</code> existe e está formatado corretamente.</p><h3 id="_2-mapeamento-de-ferramentas-nao-funcionando" tabindex="-1">2. Mapeamento de Ferramentas Não Funcionando <a class="header-anchor" href="#_2-mapeamento-de-ferramentas-nao-funcionando" aria-label="Permalink to &quot;2. Mapeamento de Ferramentas Não Funcionando&quot;">​</a></h3><p><strong>Problema</strong>: A IA ainda chama nomes de ferramentas do Claude, causando erros.</p><p><strong>Causa</strong>: O conteúdo da skill pode estar contornando o guia de mapeamento de ferramentas, ou usando chamadas de ferramentas hardcoded.</p><p><strong>Solução</strong>:</p><ul><li>Confirme que a skill é usada após ser carregada, não chamando ferramentas diretamente</li><li>Se a skill tiver exemplos de código, altere manualmente os nomes das ferramentas para o formato OpenCode</li></ul><h3 id="_3-conflito-de-nomes-de-skills" tabindex="-1">3. Conflito de Nomes de Skills <a class="header-anchor" href="#_3-conflito-de-nomes-de-skills" aria-label="Permalink to &quot;3. Conflito de Nomes de Skills&quot;">​</a></h3><p><strong>Problema</strong>: Skills com mesmo nome em locais diferentes, versão errada sendo carregada.</p><p><strong>Causa</strong>: Sobrescrita devido à prioridade de descoberta de skills.</p><p><strong>Solução</strong>:</p><ul><li>Verifique o campo <code>source</code> da skill para confirmar a origem</li><li>Use o formato de namespace para especificar explicitamente a origem: <code>use_skill(skill=&quot;user:nome-da-skill&quot;)</code> ou <code>use_skill(skill=&quot;claude-plugins:nome-da-skill&quot;)</code></li></ul><details class="details custom-block"><summary>Sintaxe de Namespace</summary><p>O plugin suporta o formato <code>namespace:nome-da-skill</code>:</p><ul><li><code>project:nome-da-skill</code> - Skill OpenCode nível projeto</li><li><code>claude-project:nome-da-skill</code> - Skill Claude nível projeto</li><li><code>user:nome-da-skill</code> - Skill OpenCode nível usuário</li><li><code>claude-user:nome-da-skill</code> - Skill Claude nível usuário</li><li><code>claude-plugins:nome-da-skill</code> - Skill do marketplace de plugins Claude</li></ul></details><h2 id="resumo-da-licao" tabindex="-1">Resumo da Lição <a class="header-anchor" href="#resumo-da-licao" aria-label="Permalink to &quot;Resumo da Lição&quot;">​</a></h2><p>O plugin OpenCode Agent Skills usa um mecanismo de compatibilidade em três camadas para reutilizar skills do Claude Code sem problemas:</p><ul><li><strong>Descoberta Automática</strong> - Escaneia skills de 6 locais, cobrindo nível projeto, nível usuário e nível plugin</li><li><strong>Mapeamento de Ferramentas</strong> - Converte automaticamente nomes de ferramentas do Claude para nomes de ferramentas do OpenCode</li><li><strong>Suporte a Formatos</strong> - Suporta tanto o formato v1 quanto v2 de plugins do Claude</li></ul><p>Não é necessário reescrever skills, basta instalar e usar, o plugin lida automaticamente com problemas de compatibilidade.</p><h2 id="previa-da-proxima-licao" tabindex="-1">Prévia da Próxima Lição <a class="header-anchor" href="#previa-da-proxima-licao" aria-label="Permalink to &quot;Prévia da Próxima Lição&quot;">​</a></h2><blockquote><p>Na próxima lição, aprenderemos sobre <strong><a href="./../superpowers-integration/">Integração com Workflow Superpowers</a></strong>.</p><p>Você aprenderá:</p><ul><li>Como habilitar o modo Superpowers</li><li>Detecção e carregamento automático de skills Superpowers</li><li>Como workflows rigorosos melhoram a eficiência do desenvolvimento</li></ul></blockquote><hr><h2 id="apendice-referencia-do-codigo-fonte" tabindex="-1">Apêndice: Referência do Código-Fonte <a class="header-anchor" href="#apendice-referencia-do-codigo-fonte" aria-label="Permalink to &quot;Apêndice: Referência do Código-Fonte&quot;">​</a></h2><details><summary><strong>Clique para expandir e ver a localização do código-fonte</strong></summary><blockquote><p>Atualizado em: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidade</th><th>Caminho do Arquivo</th><th>Linhas</th></tr></thead><tbody><tr><td>Definição de mapeamento de ferramentas</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L19-L25" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>19-25</td></tr><tr><td>Definição de tipos de formato v1/v2</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L35-L61" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>35-61</td></tr><tr><td>Extração de caminho de instalação de plugin</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L68-L77" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>68-77</td></tr><tr><td>Descoberta de skills de plugin</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L82-L105" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>82-105</td></tr><tr><td>Descoberta de skills do marketplace</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L115-L180" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>115-180</td></tr><tr><td>Descoberta de skills em cache</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L193-L253" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>193-253</td></tr><tr><td>Lista de prioridade de descoberta de skills</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L241-L254" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>241-254</td></tr><tr><td>Lógica de deduplicação de skills com mesmo nome</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L256-L260" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>256-260</td></tr><tr><td>Import de toolTranslation</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/tools.ts#L15" target="_blank" rel="noreferrer"><code>src/tools.ts</code></a></td><td>15</td></tr><tr><td>Injeção de mapeamento de ferramentas</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/tools.ts#L238-L249" target="_blank" rel="noreferrer"><code>src/tools.ts</code></a></td><td>238-249</td></tr></tbody></table><p><strong>Constantes-Chave</strong>:</p><ul><li><code>toolTranslation</code>: String XML do guia de mapeamento de ferramentas, injetada no contexto da sessão ao carregar skills. Definida em <code>src/claude.ts:19-25</code>, importada em <code>src/tools.ts:15</code></li></ul><p><strong>Funções-Chave</strong>:</p><ul><li><code>getPluginInstallPaths()</code>: Extrai caminhos de instalação de plugins dos formatos v1/v2</li><li><code>discoverSkillsFromPluginDir()</code>: Escaneia o subdiretório skills/ do diretório de plugins</li><li><code>discoverMarketplaceSkills()</code>: Descobre skills de <code>~/.claude/plugins/marketplaces/</code> (prioritário)</li><li><code>discoverPluginCacheSkills()</code>: Descobre skills de <code>~/.claude/plugins/cache/</code> (como fallback)</li><li><code>findFile()</code>: Busca recursivamente por nome de arquivo especificado (função utilitária)</li></ul><p><strong>Fluxo Importante</strong>:</p><ol><li>Na inicialização do plugin, chama <code>discoverAllSkills()</code> → percorre 6 caminhos de descoberta</li><li>Ao descobrir skills de plugins do Claude, chama <code>discoverMarketplaceSkills()</code> ou <code>discoverPluginCacheSkills()</code></li><li>Ao carregar skill, a ferramenta <code>use_skill</code> insere <code>toolTranslation</code> no conteúdo XML (linha 244)</li></ol></details>`,68)])])}const h=a(i,[["render",l]]);export{u as __pageData,h as default};
